import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './ToReprice.css';
import pacman from './Icons/pacman.svg';
import pricesens from './Icons/pricesensitivity.svg';
import euro from './Icons/euro.svg';

const ToReprice = () => {
    const [items, setItems]     = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError]     = useState(null);
    const [search, setSearch]   = useState('');
    const [selectedIndex, setSelectedIndex] = useState(0);

    useEffect(() => {
        async function load() {
            try {
                const res = await axios.get(
                    `${process.env.REACT_APP_API_URL || 'http://localhost:3007'}/api/menu-items`,
                    { withCredentials: true }
                );

                // map supabase rows into your old "allItems" shape:
                const mapped = res.data.map((i) => ({
                    name:                 i.item_name,
                    currentPrice:         i.price,
                    minPrice:             i.floor_price,
                    maxPrice:             i.ceiling_price,
                    optimalPrice:         (i.low_price + i.high_price) / 2,
                    cannibalisationRisk:  'medium',  // TODO: replace with real logic
                    priceSensitivity:     'medium',  // TODO
                    jouwPrijsIs:          'goed'     // TODO
                }));

                setItems(mapped);
            } catch (err) {
                console.error(err);
                setError('Kon data niet laden');
            } finally {
                setLoading(false);
            }
        }
        load();
    }, []);

    if (loading) return <div className="loading">Loading…</div>;
    if (error)   return <div className="error">{error}</div>;

    // sort descending by optimalPrice (for example)
    const sorted = [...items].sort((a,b) => b.optimalPrice - a.optimalPrice);

    // filter safely – only call toLowerCase if name is a string
    const filtered = sorted.filter(item =>
        typeof item.name === 'string' &&
        item.name.toLowerCase().includes(search.toLowerCase())
    );

    const selected = filtered[selectedIndex] || {};
    const cp = selected.currentPrice?.toFixed(2) || '0.00';
    const op = selected.optimalPrice?.toFixed(2)   || '0.00';
    const mn = selected.minPrice?.toFixed(2)       || '0.00';
    const mx = selected.maxPrice?.toFixed(2)       || '0.00';

    // now your chart math…
    const minP = parseFloat(mn);
    const maxP = parseFloat(mx);
    const optP = parseFloat(op);
    const currP = parseFloat(cp);

    const percent = p => ((p - minP) / (maxP - minP)) * 100;
    const thresholds = [minP, (optP*0.5), (optP*0.7), (optP*1.25), (optP*1.5), maxP];
    const weights = thresholds.slice(1).map((t,i) => t - thresholds[i]);

    return (
        <div className="to-reprice-container">
            <div className="controls">
                <input
                    type="text"
                    placeholder="Search items…"
                    value={search}
                    onChange={e => setSearch(e.target.value)}
                />
            </div>

            <div className="price-bar-wrapper">
                {thresholds.map((t,i) => (
                    <div
                        key={i}
                        className={`threshold-label ${i===0||i===thresholds.length-1?'end':''}`}
                        style={{ left: `calc(${percent(t)}% - 12px)` }}
                    >
                        €{t.toFixed(2)}
                    </div>
                ))}

                <div
                    className="indicator optimal"
                    style={{ left: `calc(${percent(optP)}% - 8px)` }}
                />
                <div
                    className="label optimal"
                    style={{ left: `calc(${percent(optP)}% - 8px)` }}
                >
                    €{op} best price
                </div>

                <div className="price-bar">
                    {weights.map((w,i) => (
                        <div key={i} className={`segment seg${i}`} style={{ flex: w }} />
                    ))}
                </div>

                <div
                    className="indicator current"
                    style={{ left: `calc(${percent(currP)}% - 8px)` }}
                />
                <div
                    className="label current"
                    style={{ left: `calc(${percent(currP)}% - 8px)` }}
                >
                    €{cp} current
                </div>
            </div>

            <ul className="items-list">
                {filtered.map((item, idx) => (
                    <li
                        key={item.name + idx}
                        className={idx === selectedIndex ? 'selected' : ''}
                        onClick={() => setSelectedIndex(idx)}
                    >
                        {idx+1}. {item.name}
                    </li>
                ))}
            </ul>

            <div className="indicators">
                <div>
                    <img src={pacman} alt="Cannibalism" />
                    <strong>Cannibalism:</strong> {selected.cannibalisationRisk}
                </div>
                <div>
                    <img src={pricesens} alt="Sensitivity" />
                    <strong>Price Sensitivity:</strong> {selected.priceSensitivity}
                </div>
                <div>
                    <img src={euro} alt="Your Price" />
                    <strong>Your Price:</strong> {selected.jouwPrijsIs}
                </div>
            </div>
        </div>
    );
};

export default ToReprice;
